class TokenBucket:
    def __init__(self, rate):
        self.tokens = rate
    def allow(self):
        if self.tokens >= 1:
            self.tokens -= 1
            return True
        return False
b = TokenBucket(2)
allows = [b.allow() for _ in range(3)]
print(sum(1 for a in allows if a))
print("third", allows[2])
print("ok", True)

def backoff(attempt, base=0.1):
    return base * (2 ** attempt)
print(backoff(3))
print("ok", True)
print("attempt", 3)
